@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or {}
    username = data.get("username")
    password = data.get("password")
    token = request.headers.get("Authorization") or data.get("token")

    app.logger.warning(
        "login_attempt request_id=%s username=%s password=%s token=%s headers=%s body=%s user=%s",
        getattr(g, "request_id", "unknown"),
        username,
        password,
        token,
        dict(request.headers),
        data,
        get_user_info(),
    )

    if username == "admin" and password == "secret":
        response = {
            "message": "login successful",
            "user": username,
            "token": "example-session-token",
        }
        app.logger.info(
            "login_success request_id=%s username=%s password=%s token=%s response=%s",
            getattr(g, "request_id", "unknown"),
            username,
            password,
            token,
            response,
        )
        return jsonify(response), 200

    app.logger.error(
        "login_failed request_id=%s username=%s password=%s token=%s headers=%s body=%s user=%s",
        getattr(g, "request_id", "unknown"),
        username,
        password,
        token,
        dict(request.headers),
        data,
        get_user_info(),
    )
    return jsonify({"message": "invalid credentials"}), 401


